#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <math.h>
#include <omp.h>

float accuracy(float *arr1, float *arr2, int len)
{
    float err = 0.0f; 
    for(int i = 0; i < len; i++)
    {
        float diff = arr1[i] - arr2[i];
        err += diff * diff;
    }
    return sqrtf(err / len);
}

void computeTempCPU(float *pIn, float* tIn, float *tOut, 
        int nx, int ny, int nz, float Cap, 
        float Rx, float Ry, float Rz, 
        float dt, float amb_temp, int numiter) 
{   
    float ce, cw, cn, cs, ct, cb, cc;
    float stepDivCap = dt / Cap;
    ce = cw = stepDivCap / Rx;
    cn = cs = stepDivCap / Ry;
    ct = cb = stepDivCap / Rz;

    cc = 1.0f - (2.0f*ce + 2.0f*cn + 3.0f*ct);

    int c,w,e,n,s,b,t;
    int x,y,z;
    int i = 0;
    do{
        for(z = 0; z < nz; z++)
            for(y = 0; y < ny; y++)
                for(x = 0; x < nx; x++)
                {
                    c = x + y * nx + z * nx * ny;

                    w = (x == 0) ? c : c - 1;
                    e = (x == nx - 1) ? c : c + 1;
                    n = (y == 0) ? c : c - nx;
                    s = (y == ny - 1) ? c : c + nx;
                    b = (z == 0) ? c : c - nx * ny;
                    t = (z == nz - 1) ? c : c + nx * ny;

                    tOut[c] = tIn[c]*cc + tIn[n]*cn + tIn[s]*cs + tIn[e]*ce + tIn[w]*cw + tIn[t]*ct + tIn[b]*cb + (dt/Cap) * pIn[c] + ct*amb_temp;
                }
        float *temp = tIn;
        tIn = tOut;
        tOut = temp; 
        i++;
    }
    while(i < numiter);
}

void hotspotOpt1(float *p, float* tIn, float *tOut, float sdc,
                            int nx, int ny, int nz,
                            float ce, float cw, 
                            float cn, float cs,
                            float ct, float cb, 
                            float cc) 
{
  float amb_temp = 80.0f;

  int xy = nx * ny;

  #pragma omp parallel for collapse(2)
  for (int j = 0; j < ny; j++) {
    for (int i = 0; i < nx; i++) {
      int c = i + j * nx;

      int W = (i == 0)        ? c : c - 1;
      int E = (nx-1 == i)     ? c : c + 1;
      int N = (j == 0)        ? c : c - nx;
      int S = (ny-1 == j)     ? c : c + nx;

      float temp1, temp2, temp3;
      temp1 = temp2 = tIn[c];
      temp3 = tIn[c+xy];
      tOut[c] = cc * temp2 + cw * tIn[W] + ce * tIn[E] + cs * tIn[S]
        + cn * tIn[N] + cb * temp1 + ct * temp3 + sdc * p[c] + ct * amb_temp;
      c += xy;
      W = W + (xy);
      E = E + (xy);
      N = N + (xy);
      S += xy;

      for (int k = 1; k < nz-1; ++k) {
          temp1 = temp2;
          temp2 = temp3;
          temp3 = tIn[c+xy];
          tOut[c] = cc * temp2 + cw * tIn[W] + ce * tIn[E] + cs * tIn[S]
            + cn * tIn[N] + cb * temp1 + ct * temp3 + sdc * p[c] + ct * amb_temp;
          c += xy;
          W = W + (xy);
          E += xy;
          N = N + (xy);
          S = S + (xy);
      }
      temp1 = temp2;
      temp2 = temp3;
      tOut[c] = cc * temp2 + cw * tIn[W] + ce * tIn[E] + cs * tIn[S]
        + cn * tIn[N] + cb * temp1 + ct * temp3 + sdc * p[c] + ct * amb_temp;
    }
  }
}

int main(int argc, char** argv)
{
    char *pfile = NULL, *tfile = NULL, *ofile = NULL;
    int iterations = 0;
    int numCols    = 0;
    int numRows    = 0;
    int layers     = 0;

    int cur_arg;
	for (cur_arg = 1; cur_arg<argc; cur_arg++) {
        if (strcmp(argv[cur_arg], "-h") == 0) {
			fprintf(stderr, "Usage: %s <-n rows/cols> <-l layers> <-i iterations> <-f powerFile tempFile outputFile>\n", argv[0]);
			fprintf(stderr, "\t<rows/cols>  - number of rows/cols in the grid (positive integer)\n");
			fprintf(stderr, "\t<layers>  - number of layers in the grid (positive integer)\n");
			fprintf(stderr, "\t<iteration> - number of iterations\n");
			fprintf(stderr, "\t<powerFile>  - name of the file containing the initial power values of each cell\n");
			fprintf(stderr, "\t<tempFile>  - name of the file containing the initial temperature values of each cell\n");
			fprintf(stderr, "\t<outputFile - output file\n");
			exit(1);
        }
        else if (strcmp(argv[cur_arg], "-n") == 0) {
            if (argc >= cur_arg + 1) {
                numCols = numRows = atoi(argv[cur_arg+1]);
                cur_arg++;
            }
        }
        else if (strcmp(argv[cur_arg], "-l") == 0) {
            if (argc >= cur_arg + 1) {
                layers = atoi(argv[cur_arg+1]);
                cur_arg++;
            }
        }
        else if (strcmp(argv[cur_arg], "-i") == 0) {
            if (argc >= cur_arg + 1) {
                iterations = atoi(argv[cur_arg+1]);
                cur_arg++;
            }
        }
        else if (strcmp(argv[cur_arg], "-f") == 0) {
            if (argc >= cur_arg + 3) {
                pfile = argv[cur_arg+1];
                tfile = argv[cur_arg+2];
                ofile = argv[cur_arg+3];
                cur_arg += 3;
            }
        }
    }

	if (numCols == 0 || layers == 0 || iterations == 0 || pfile == NULL || tfile == NULL || ofile == NULL) {
		fprintf(stderr, "Usage: %s <-n rows/cols> <-l layers> <-i iterations> <-f powerFile tempFile outputFile>\n", argv[0]);
		exit(1);
	}

  const float FACTOR_CHIP = 0.5f;
  const float SPEC_HEAT_SI = 1.75e6f;
  const float K_SI = 100.0f;
  const float t_chip = 0.0005f;
  const float chip_height = 0.016f;
  const float chip_width = 0.016f;
  const float amb_temp = 80.0f;
  const float MAX_PD = 3.0e6f;
  const float PRECISION = 0.001f;

  float dx = chip_height / numRows;
  float dy = chip_width / numCols;
  float dz = t_chip / layers;

  float Cap = FACTOR_CHIP * SPEC_HEAT_SI * t_chip * dx * dy;
  float Rx = dy / (2.0f * K_SI * t_chip * dx);
  float Ry = dx / (2.0f * K_SI * t_chip * dy);
  float Rz = dz / (K_SI * dx * dy);

  float max_slope = MAX_PD / (FACTOR_CHIP * t_chip * SPEC_HEAT_SI);
  float dt = PRECISION / max_slope;

  float stepDivCap = dt / Cap;
  float ce = stepDivCap / Rx;
  float cw = ce;
  float cn = stepDivCap / Ry;
  float cs = cn;
  float ct = stepDivCap / Rz;
  float cb = ct;
  float cc = 1.0f - (2.0f * ce + 2.0f * cn + 3.0f * ct);

  int size = numCols * numRows * layers;
  float* tIn = (float*) calloc(size, sizeof(float));
  float* pIn = (float*) calloc(size, sizeof(float));
  float* tempOut = (float*) calloc(size, sizeof(float));
  float* tempCopy = (float*) malloc(size * sizeof(float));
  if (!tIn || !pIn || !tempOut || !tempCopy) {
    fprintf(stderr, "Memory allocation failed\n");
    return 1;
  }

  FILE *fp;

  fp = fopen(tfile, "r");
  if (!fp) {
    fprintf(stderr, "Failed to open temperature input file\n");
    return 1;
  }
  for (int i = 0; i < size; i++) {
    if (fscanf(fp, "%f", &tIn[i]) != 1) {
      fprintf(stderr, "Error reading temperature input file\n");
      fclose(fp);
      return 1;
    }
  }
  fclose(fp);

  fp = fopen(pfile, "r");
  if (!fp) {
    fprintf(stderr, "Failed to open power input file\n");
    return 1;
  }
  for (int i = 0; i < size; i++) {
    if (fscanf(fp, "%f", &pIn[i]) != 1) {
      fprintf(stderr, "Error reading power input file\n");
      fclose(fp);
      return 1;
    }
  }
  fclose(fp);

  memcpy(tempCopy, tIn, size * sizeof(float));

  for (int iter = 0; iter < iterations; iter++) {
    hotspotOpt1(pIn, tIn, tempOut, stepDivCap, numCols, numRows, layers, ce, cw, cn, cs, ct, cb, cc);
    float* tmp = tIn;
    tIn = tempOut;
    tempOut = tmp;
  }

  float* answer = (float*) calloc(size, sizeof(float));
  if (!answer) {
    fprintf(stderr, "Memory allocation failed\n");
    free(tIn);
    free(pIn);
    free(tempOut);
    free(tempCopy);
    return 1;
  }
  computeTempCPU(pIn, tempCopy, answer, numCols, numRows, layers, Cap, Rx, Ry, Rz, dt, amb_temp, iterations);
  float acc = accuracy(tIn, answer, size);
  printf("Accuracy: %e\n", acc);

  fp = fopen(ofile, "w");
  if (!fp) {
    fprintf(stderr, "Failed to open output file\n");
    free(tIn);
    free(pIn);
    free(tempOut);
    free(tempCopy);
    free(answer);
    return 1;
  }
  int index = 0;
  for (int i = 0; i < numRows; i++) {
    for (int j = 0; j < numCols; j++) {
      for (int k = 0; k < layers; k++) {
        fprintf(fp, "%d\t%g\n", index, tIn[i * numCols + j + k * numRows * numCols]);
        index++;
      }
    }
  }
  fclose(fp);

  free(tIn);
  free(pIn);
  free(tempOut);
  free(tempCopy);
  free(answer);

  return 0;
}
